<script setup lang="ts">
import { computed } from 'vue';
import { useRouter } from 'vue-router';
import { Check, Clock, X, Home, ChevronRight } from 'lucide-vue-next';
import { useRollCallStore } from '@/store/useRollCallStore';
import { useAdminStore } from '@/store/useAdminStore';
import { FLOORS } from '@/data/mockData';
import type { Merchant } from '@/types';
import dayjs from 'dayjs';

const router = useRouter();
const store = useRollCallStore();
const adminStore = useAdminStore();

const TODAY = computed(() => dayjs().format('YYYY-MM-DD'));

const STATUS_BADGE = {
  signedIn: { label: '已到岗', bg: 'bg-green-50 dark:bg-green-500/15', text: 'text-[#16A34A] dark:text-green-400', border: 'border-green-200 dark:border-green-500/30', dot: '#16A34A' },
  unsigned: { label: '未签到', bg: 'bg-amber-50 dark:bg-amber-500/15', text: 'text-[#F59E0B] dark:text-amber-400', border: 'border-amber-200 dark:border-amber-500/30', dot: '#F59E0B' },
  absent: { label: '缺勤', bg: 'bg-red-50 dark:bg-red-500/15', text: 'text-[#EF4444] dark:text-red-400', border: 'border-red-200 dark:border-red-500/30', dot: '#EF4444' },
} as const;

function statusOf(m: Merchant) {
  if (m.signedIn) return 'signedIn' as const;
  if (m.absent) return 'absent' as const;
  return 'unsigned' as const;
}

const SUMMARY = [
  { key: 'signedIn', icon: Check, iconBg: 'bg-[#22C55E]/20', iconColor: '#22C55E', cardBg: 'bg-green-50 dark:bg-green-500/15', numColor: 'text-[#16A34A] dark:text-green-400', sub: '已到岗' },
  { key: 'unsigned', icon: Clock, iconBg: 'bg-[#F59E0B]/20', iconColor: '#F59E0B', cardBg: 'bg-amber-50 dark:bg-amber-500/15', numColor: 'text-[#D97706] dark:text-amber-400', sub: '未签到' },
  { key: 'absent', icon: X, iconBg: 'bg-[#EF4444]/20', iconColor: '#EF4444', cardBg: 'bg-red-50 dark:bg-red-500/15', numColor: 'text-[#EF4444] dark:text-red-400', sub: '缺勤率' },
  { key: 'total', icon: Home, iconBg: 'bg-[#3B82F6]/20', iconColor: '#3B82F6', cardBg: 'bg-blue-50 dark:bg-blue-500/15', numColor: 'text-[#3B82F6] dark:text-blue-400', sub: '总商户' },
] as const;

const todayRecords = computed(() => adminStore.records.filter((r) => r.date === TODAY.value));
const todaySignedIn = computed(() => todayRecords.value.filter((r) => r.status === 'signedIn').length);
const todayAbsent = computed(() => todayRecords.value.filter((r) => r.status === 'absent').length);
const todayUnsigned = computed(() => todayRecords.value.filter((r) => r.status === 'unsigned').length);
const total = computed(() => store.merchants.length);

const filtered = computed(() =>
  store.activeFloor === '全部' ? store.merchants : store.merchants.filter((m) => m.floor === store.activeFloor)
);

function pct(n: number) {
  return total.value === 0 ? 0 : Math.round((n / total.value) * 100);
}

const summaryData = computed(() => ({
  signedIn: { count: todaySignedIn.value, pct: `${pct(todaySignedIn.value)}%` },
  unsigned: { count: todayUnsigned.value, pct: `${pct(todayUnsigned.value)}%` },
  absent: { count: todayAbsent.value, pct: `${pct(todayAbsent.value)}%` },
  total: { count: total.value, pct: '100%' },
}));

const dateLabel = dayjs().format('YYYY年M月D日');
</script>

<template>
  <div class="flex h-full flex-col overflow-y-auto bg-base pb-20 no-scrollbar">
    <div class="flex flex-col gap-2 px-gutter">
      <!-- 顶部标题区 -->
      <div class="rounded-card bg-card px-4 pb-3 pt-4">
        <div>
          <h1 class="text-xl font-bold text-ink">商户</h1>
          <p class="mt-0.5 text-xs text-muted">管理商户签到状态及信息</p>
        </div>
      </div>

      <!-- 今日概览卡片 -->
      <div class="rounded-card bg-card p-4 shadow-sm">
        <div class="mb-3 flex items-center justify-between">
          <span class="text-sm font-semibold text-ink">今日概览</span>
          <span class="text-xs text-muted">{{ dateLabel }}</span>
        </div>
        <div class="grid grid-cols-2 gap-2.5">
          <div
            v-for="c in SUMMARY"
            :key="c.key"
            class="flex items-center gap-3 rounded-xl p-3"
            :class="c.cardBg"
          >
            <div class="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg" :class="c.iconBg">
              <component :is="c.icon" :size="20" :color="c.iconColor" :stroke-width="2" />
            </div>
            <div>
              <p class="text-xl font-bold" :class="c.numColor">
                {{ summaryData[c.key].count
                }}<span class="ml-0.5 text-[10px] font-normal text-muted">户</span>
              </p>
              <p class="whitespace-nowrap text-[11px]" :class="c.numColor">
                {{ c.sub }} · {{ summaryData[c.key].pct }}
              </p>
            </div>
          </div>
        </div>
      </div>

      <!-- 楼层标签 -->
      <div class="rounded-card bg-card p-3 shadow-sm">
        <div class="no-scrollbar flex items-center gap-2 overflow-x-auto">
          <button
            v-for="f in FLOORS"
            :key="f"
            type="button"
            class="shrink-0 rounded-full px-4 py-1.5 text-[13px] font-medium transition-colors"
            :class="store.activeFloor === f ? 'bg-primary text-white' : 'bg-base text-ink active:bg-base'"
            @click="store.setActiveFloor(f)"
          >
            {{ f }}
          </button>
        </div>
      </div>

      <!-- 商户列表 -->
      <div class="space-y-2.5">
        <button
          v-for="m in filtered"
          :key="m.id"
          type="button"
          class="block w-full rounded-2xl bg-card p-3.5 text-left shadow-sm transition-transform active:scale-[0.98]"
          @click="router.push(`/merchant/${m.id}`)"
        >
          <div class="flex items-center gap-3">
            <img
              v-if="m.avatar"
              :src="m.avatar"
              :alt="m.name"
              class="h-10 w-10 shrink-0 rounded-xl object-cover"
            />
            <div
              v-else
              class="flex h-10 w-10 shrink-0 items-center justify-center rounded-xl bg-primary-light text-[13px] font-semibold text-primary"
            >
              {{ m.name.slice(0, 2) }}
            </div>
            <div class="min-w-0 flex-1">
              <div class="flex items-center">
                <span class="truncate text-sm font-semibold text-ink">{{ m.name }}</span>
              </div>
              <div class="mt-1 text-xs text-muted">{{ m.location }}</div>
            </div>
            <span
              class="inline-flex shrink-0 self-center items-center rounded-full border px-2.5 py-1 text-xs font-medium"
              :class="[STATUS_BADGE[statusOf(m)].bg, STATUS_BADGE[statusOf(m)].text, STATUS_BADGE[statusOf(m)].border]"
            >
              <span
                class="mr-1 inline-block h-1.5 w-1.5 rounded-full"
                :style="{ backgroundColor: STATUS_BADGE[statusOf(m)].dot }"
              />
              {{ STATUS_BADGE[statusOf(m)].label }}
            </span>
            <ChevronRight :size="14" class="shrink-0 text-[#D1D5DB]" />
          </div>
        </button>
        <div v-if="filtered.length === 0" v-motion :initial="{opacity:0}" :enter="{opacity:1, transition:{duration:300}}" class="py-10 text-center text-sm text-muted">
          当前楼层暂无商户
        </div>
      </div>
    </div>
  </div>
</template>
